class Solution(object):
    def minAllOneMultiple(self, k):
        # If k shares a factor with 10 (i.e., divisible by 2 or 5),
        # no repunit can be divisible by k
        if k % 2 == 0 or k % 5 == 0:
            return -1
        remainder = 0
        for length in range(1, k + 1):
            remainder = (remainder * 10 + 1) % k
            if remainder == 0:
                return length
        return -1
